INSERT INTO books (title, author, publisher, year, pages, category, language, synopsis, moral) VALUES
  ('爱上 时光','李明华','花城出版社',1995,400,'小说','Cina','这部作品以时光为主题，描绘了人生百态与内心世界的深刻探索。作者用细腻的笔触带领读者进入一段难忘的阅读旅程。','坚持梦想，勇于面对困难，是通往成功的必由之路。'),
  ('爱上 岁月','张晓燕','商务印书馆',1996,88,'散文','Cina','通过岁月这一主题，作者展现了人与人之间深厚的情感纽带。这是一部令人感动、发人深省的文学佳作。','珍惜身边的人与物，感恩生活中的每一份美好。'),
  ('爱上 青春','王建国','中华书局',1997,97,'诗歌','Cina','本书围绕青春展开叙述，讲述了一个关于成长、梦想与坚持的动人故事，充满了对生命意义的深刻思考。','诚实守信、善良宽容是做人处世的根本准则。'),
  ('爱上 往事','陈美玲','人民文学出版社',1998,106,'传记','Cina','以往事为线索，作者编织了一幅丰富多彩的人生画卷，展现了不同人物面对命运时的抉择与坚守。','学无止境，不断学习与进步是人生最宝贵的财富。'),
  ('爱上 故事','刘志远','南方出版社',1999,115,'历史','Cina','这部作品以独特的视角诠释了故事的深刻内涵，带给读者对生活、对人性的全新认识与感悟。','家庭、友情与爱是人生中最重要的精神支柱。'),
  ('爱上 记忆','林静怡','花城出版社',2000,124,'哲学','Cina','书中以记忆为背景，描述了主人公在面对人生考验时展现出的勇气与智慧，令人深受鼓舞。','坚持梦想，勇于面对困难，是通往成功的必由之路。'),
  ('爱上 梦想','黄文华','商务印书馆',2001,133,'科学','Cina','作者以优美的文字描绘了梦想的种种面貌，探索了人类情感的丰富层次与生命的无限可能。','珍惜身边的人与物，感恩生活中的每一份美好。'),
  ('爱上 希望','赵丽娟','中华书局',2002,142,'励志','Cina','这是一部关于希望的深情之作，通过真实的人物与故事，触动每一位读者内心最柔软的角落。','诚实守信、善良宽容是做人处世的根本准则。'),
  ('爱上 未来','吴国强','人民文学出版社',2003,151,'儿童文学','Cina','本书探讨了未来对于个人成长与社会发展的重要意义，是一部兼具文学价值与思想深度的优秀作品。','学无止境，不断学习与进步是人生最宝贵的财富。'),
